def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        cap = bins[i]
        if cap == 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / cap
        if usage_ratio > 1:
            penalty = 1000 * usage_ratio
            if usage_ratio > 2:
                penalty += 500
            priorities[i] = penalty
        elif usage_ratio == 1:
            priorities[i] = 20
        else:
            diff = 1 - usage_ratio
            log_val = np.log(diff + 1e-9)
            if log_val < -3:
                priorities[i] = -log_val * 8
            elif log_val < -1:
                priorities[i] = -log_val * 4
            else:
                priorities[i] = -log_val
            if diff < 0.05:
                priorities[i] += 15
            elif diff < 0.1:
                priorities[i] += 5
        if cap < 0.05:
            priorities[i] += 70
        elif cap < 0.15:
            priorities[i] += 20
        fraction = cap - int(cap)
        if fraction > 0.8:
            priorities[i] += 7
        elif fraction > 0.5:
            priorities[i] += 3
        digits = str(cap)
        count_nines = digits.count('9')
        for _ in range(count_nines):
            priorities[i] += 1.5
        if i % 2 == 0:
            priorities[i] *= 0.9
        else:
            priorities[i] *= 1.1
    if np.any(bins == 0):
        priorities[bins == 0] = np.inf
    return priorities
